+    CATLASS_DEVICE
+    bool IsSyncTask(int32_t task_id, int32_t n_tasks) {
+        int32_t offset = n_tasks - task_id;
+        if (offset <= 0 || (offset & (offset - 1)) != 0) {
+            return false;
+        }else
+        {
+            return true;
+        }
+    }
