+
+inline static int64_t AlignOneBlockByte(int64_t x) {
+  return (x + ONE_BLOCK_BYTE - 1) / ONE_BLOCK_BYTE * ONE_BLOCK_BYTE;
+}
+
+inline static int64_t AlignOneBlockByteCeil(int64_t x) {
+  return x / ONE_BLOCK_BYTE * ONE_BLOCK_BYTE;
+}
