+        }
+        outOffset = outIndex * cols + colsLoop * this->perLoopCols;
+        DataCopyPad(expandedXGm[outOffset], outLocal, intriParams);
+      }
+      inputXCopyInQueue.FreeTensor(inLocal);
+      inputXCopyOutQueue.FreeTensor(outLocal);
+    }
+  }
