+      if (loop == this->rowLoops - 1) {
+        currentLoopRows = lastLoopRows;
+      }
+      CopyInIndices(loop);
+      CopyOut(loop);
+    }
+  }
+}
+}  // namespace MoeInitRoutingQuantV2
+#endif  // MOE_V2_GATHER_QUANT_H

