+template <typename T1, typename T2, typename T3, bool PROBS>
+__aicore__ inline void
+KernelMoeTokenUnpermute<T1, T2, T3, PROBS>::Init(GM_ADDR permuted_tokens, GM_ADDR sorted_indices, GM_ADDR probs,
